function linearExpression(value, inputMin, inputMax, outputMin, outputMax) {
  var normalizedValue = (value - inputMin) / (inputMax - inputMin);
  var outputValue = outputMin + normalizedValue * (outputMax - outputMin);
  return Math.max(Math.min(outputValue, Math.max(outputMin, outputMax)), Math.min(outputMin, outputMax));
}

var controllingValue = thisComp.layer("Driver Null")("Effects")("Slider Control")("Slider").value;
var minVal = 0;
var maxVal = 100;
if (controllingValue < minVal) controllingValue = minVal;
if (controllingValue > maxVal) controllingValue = maxVal;
var segments = [[[0],[50]],[[50],[100]]];
var relativeTimes = [0,0.5,1];
var evenInterpolation = thisComp.layer('Driver Null')('Effects')('Uniform Interpolation ||Target Shape>Transform>Opacity')('Checkbox').value;
function mapSliderToValue(controllingValue, segments, minVal, maxVal, relativeTimes, evenInterpolation) {
  var numSegments = segments.length;
  var mappedValue;
  for (var i = 0; i < numSegments; i++) {
    var segmentStart, segmentEnd, valueStart, valueEnd;
    if (evenInterpolation) {
      segmentStart = minVal + i * (maxVal - minVal) / numSegments;
      segmentEnd = minVal + (i + 1) * (maxVal - minVal) / numSegments;
      valueStart = segments[i][0][0];
      valueEnd = segments[i][1][0];
    } else {
      segmentStart = minVal + relativeTimes[i] * (maxVal - minVal);
      segmentEnd = minVal + relativeTimes[i + 1] * (maxVal - minVal);
      valueStart = segments[i][0][0];
      valueEnd = segments[i][1][0];
    }
    if (segmentStart === segmentEnd) {
      segmentEnd += 0.0001;
    }
    if (controllingValue >= segmentStart && controllingValue <= segmentEnd) {
      mappedValue = linearExpression(controllingValue, segmentStart, segmentEnd, valueStart, valueEnd);
      break;
    }
  }
  if (controllingValue < minVal) {
    mappedValue = segments[0][0][0];
  }
  if (controllingValue > maxVal) {
    mappedValue = segments[numSegments - 1][1][0];
  }
  return mappedValue;
}

var mappedValue = mapSliderToValue(controllingValue, segments, minVal, maxVal, relativeTimes, evenInterpolation);
value = mappedValue;
